import os
import sys
import tarfile
import zipfile
import subprocess

def backup_dir(dir_path, format):
    base_name = os.path.basename(dir_path.rstrip(os.sep))
    
    if format == 'tar.gz':
        archive_name = base_name + '.tar.gz'
        with tarfile.open(archive_name, "w:gz") as tar:
            tar.add(dir_path, arcname=os.path.basename(dir_path))
    elif format == 'tar.bz2':
        archive_name = base_name + '.tar.bz2'
        with tarfile.open(archive_name, "w:bz2") as tar:
            tar.add(dir_path, arcname=os.path.basename(dir_path))
    elif format == 'zip':
        archive_name = base_name + '.zip'
        with zipfile.ZipFile(archive_name, 'w', zipfile.ZIP_DEFLATED) as z:
            for root, dirs, files in os.walk(dir_path):
                for file in files:
                    abs_path = os.path.join(root, file)
                    z.write(abs_path, abs_path[len(dir_path)+len(os.sep):])            
    elif format == '7z':
        archive_name = base_name + '.7z'
        if subprocess.call(['7z', 'a', archive_name, dir_path]) == 0:
            print('Successfully created: ' + archive_name)
        else:
            print('An error occurred during the 7z operation.')

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: script.py [directory_path] [format]")
    else:
        backup_dir(sys.argv[1], sys.argv[2])